@app.route("/documents", methods=["POST"])
def create_document():
    data = request.get_json(silent=True) or {}

    required_fields = ["title", "content", "author_id"]
    missing = [field for field in required_fields if not data.get(field)]
    if missing:
        return jsonify({"error": f"Missing required fields: {', '.join(missing)}"}), 400

    author_oid = parse_object_id(data["author_id"])
    if not author_oid:
        return jsonify({"error": "Invalid author_id"}), 400

    author = users_collection.find_one({"_id": author_oid})
    if not author:
        return jsonify({"error": "Author not found"}), 404

    doc = {
        "title": data["title"],
        "content": data["content"],
        "author_id": author_oid,
        "status": data.get("status", "draft"),
        "tags": data.get("tags", []),
        "metadata": data.get("metadata", {}),
        "created_at": datetime.utcnow(),
        "updated_at": datetime.utcnow(),
    }

    result = documents_collection.insert_one(doc)
    created = documents_collection.find_one({"_id": result.inserted_id})
    return jsonify(serialize_doc(created)), 201


@app.route("/documents", methods=["GET"])
def query_documents():
    query = {}

    author_id = request.args.get("author_id")
    status = request.args.get("status")
    tag = request.args.get("tag")
    title = request.args.get("title")
    created_after = request.args.get("created_after")
    created_before = request.args.get("created_before")
    sort_by = request.args.get("sort_by", "created_at")
    sort_order = request.args.get("sort_order", "desc").lower()

    if author_id:
        author_oid = parse_object_id(author_id)
        if not author_oid:
            return jsonify({"error": "Invalid author_id"}), 400
        query["author_id"] = author_oid

    if status:
        query["status"] = status

    if tag:
        query["tags"] = tag

    if title:
        query["title"] = {"$regex": title, "$options": "i"}

    date_filter = {}
    if created_after:
        try:
            date_filter["$gte"] = datetime.fromisoformat(created_after)
        except ValueError:
            return jsonify({"error": "Invalid created_after datetime format. Use ISO format."}), 400
    if created_before:
        try:
            date_filter["$lte"] = datetime.fromisoformat(created_before)
        except ValueError:
            return jsonify({"error": "Invalid created_before datetime format. Use ISO format."}), 400
    if date_filter:
        query["created_at"] = date_filter

    limit = min(int(request.args.get("limit", 50)), 200)
    skip = max(int(request.args.get("skip", 0)), 0)
    direction = DESCENDING if sort_order == "desc" else ASCENDING

    allowed_sort_fields = {"created_at", "updated_at", "title", "status"}
    if sort_by not in allowed_sort_fields:
        return jsonify({"error": f"Invalid sort_by. Allowed: {', '.join(sorted(allowed_sort_fields))}"}), 400

    docs = list(
        documents_collection.find(query)
        .sort(sort_by, direction)
        .skip(skip)
        .limit(limit)
    )
    return jsonify([serialize_doc(doc) for doc in docs]), 200


