@app.route("/documents/search", methods=["POST"])
def advanced_document_query():
    data = request.get_json(silent=True) or {}
    query = data.get("query", {})
    projection = data.get("projection")
    sort = data.get("sort", [("created_at", -1)])
    limit = min(int(data.get("limit", 50)), 200)
    skip = max(int(data.get("skip", 0)), 0)

    if "author_id" in query and isinstance(query["author_id"], str):
        author_oid = parse_object_id(query["author_id"])
        if not author_oid:
            return jsonify({"error": "Invalid author_id in query"}), 400
        query["author_id"] = author_oid

    cursor = documents_collection.find(query, projection).skip(skip).limit(limit)

    if isinstance(sort, list):
        normalized_sort = []
        for item in sort:
            if isinstance(item, (list, tuple)) and len(item) == 2:
                field, direction = item
                normalized_sort.append((field, DESCENDING if int(direction) == -1 else ASCENDING))
        if normalized_sort:
            cursor = cursor.sort(normalized_sort)

    docs = list(cursor)
    return jsonify([serialize_doc(doc) for doc in docs]), 200


@app.route("/analytics/documents/by-status", methods=["GET"])
def aggregate_documents_by_status():
    pipeline = [
        {
            "$group": {
                "_id": "$status",
                "count": {"$sum": 1},
                "latest_created_at": {"$max": "$created_at"},
            }
        },
        {"$sort": {"count": -1, "_id": 1}},
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify([serialize_doc(result) for result in results]), 200


